import { useState, useEffect } from 'react';
import { getApiBase } from '../utils/platform';
import usePageTitle from '../hooks/usePageTitle';
import s from './AIUsagePage.module.css';

function authHeaders() {
  const token = localStorage.getItem('aura_token');
  return token ? { Authorization: `Bearer ${token}` } : {};
}

function formatTokens(n) {
  if (n >= 1_000_000) return `${(n / 1_000_000).toFixed(2)}M`;
  if (n >= 1_000) return `${(n / 1_000).toFixed(1)}K`;
  return String(n);
}

function StatCard({ label, value, accent, sub }) {
  return (
    <div className={s.statCard}>
      <div className={s.statLabel}>{label}</div>
      <div className={s.statValue} style={{ color: accent }}>
        {value}
      </div>
      {sub && <div className={s.statSub}>{sub}</div>}
    </div>
  );
}

function DailyChart({ daily }) {
  if (!daily || daily.length === 0) {
    return <div className={s.chartEmpty}>No usage data yet</div>;
  }

  const maxTokens = Math.max(1, ...daily.map((d) => d.tokens ?? 0));

  return (
    <div className={s.chartScroll}>
      <div className={s.chartBars} style={{ minWidth: daily.length * 24 }}>
        {daily.map((d) => {
          const h = Math.max(4, (d.tokens / maxTokens) * 140);
          return (
            <div
              key={d.day}
              className={s.barCol}
              title={`${d.day}: ${formatTokens(d.tokens)} tokens, ${d.requests} requests`}
            >
              <div className={s.bar} style={{ height: h }} />
              <div className={s.barLabel}>{d.day.slice(5)}</div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

function ModelBreakdown({ byModel }) {
  if (!byModel || byModel.length === 0) return null;

  const total = byModel.reduce((sum, m) => sum + m.tokens, 0) || 1;

  return (
    <div>
      {byModel.map((m) => {
        const pct = (m.tokens / total) * 100;
        const color = m.model === 'sonnet'
          ? 'var(--color-blue, #60A5FA)'
          : 'var(--color-purple, #A78BFA)';
        return (
          <div key={m.model} className={s.modelRow}>
            <div className={s.modelMeta}>
              <span className={s.modelName}>{m.model}</span>
              <span className={s.modelTokens}>
                {formatTokens(m.tokens)} ({pct.toFixed(0)}%)
              </span>
            </div>
            <div className={s.modelTrack}>
              <div
                className={s.modelFill}
                style={{ width: `${pct}%`, background: color }}
              />
            </div>
          </div>
        );
      })}
    </div>
  );
}

export default function AIUsagePage() {
  usePageTitle('AI Usage');
  const [usage, setUsage] = useState(null);
  const [status, setStatus] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([
      fetch(`${getApiBase()}/subscriptions/usage?days=30`, { headers: authHeaders() }).then((r) => r.json()),
      fetch(`${getApiBase()}/assistant/status`, { headers: authHeaders() }).then((r) => r.json()),
    ]).then(([usageData, statusData]) => {
      setUsage(usageData);
      setStatus(statusData);
      setLoading(false);
    }).catch(() => setLoading(false));
  }, []);

  if (loading) {
    return (
      <div className={s.loadingWrap}>
        <div className={s.loadingText}>Loading usage data...</div>
      </div>
    );
  }

  if (!status?.enabled) {
    return (
      <div className={s.disabledPage}>
        <h1 className={s.disabledTitle}>AI Usage</h1>
        <div className={s.disabledText}>
          Enable the AI Assistant to see usage analytics.
          <a href="/ai/subscription" className={s.disabledLink}>
            Get started
          </a>
        </div>
      </div>
    );
  }

  const budgetColor = status.budget?.pct_used > 90
    ? 'var(--color-red, #EF4444)'
    : status.budget?.pct_used > 70
      ? 'var(--color-amber, #F59E0B)'
      : 'var(--color-purple, #A78BFA)';

  return (
    <div className={s.page}>
      <h1 className={s.title}>AI Usage Analytics</h1>
      <p className={s.subtitle}>Last 30 days of AI assistant usage</p>

      {/* Summary cards */}
      <div className={s.statRow}>
        <StatCard
          label="Total Requests"
          value={usage?.request_count || 0}
          accent="var(--color-blue, #60A5FA)"
        />
        <StatCard
          label="Tokens Used"
          value={formatTokens(usage?.total_tokens || 0)}
          accent="var(--color-purple, #A78BFA)"
          sub={status?.budget ? `of ${formatTokens(status.budget.limit)} limit` : undefined}
        />
        <StatCard
          label="Cost"
          value={`$${(usage?.total_cost_usd || 0).toFixed(2)}`}
          accent="var(--color-green, #22C55E)"
        />
        <StatCard
          label="Cache Hit Rate"
          value={`${usage?.cache_hit_rate || 0}%`}
          accent="var(--color-amber, #F59E0B)"
        />
      </div>

      {/* Budget bar */}
      {status?.budget && (
        <div className={s.budgetCard}>
          <div className={s.budgetHeader}>
            <span className={s.budgetLabel}>Monthly Budget</span>
            <span className={s.budgetValue}>
              {formatTokens(status.budget.used)} / {formatTokens(status.budget.limit)}
            </span>
          </div>
          <div className={s.budgetTrack}>
            <div
              className={s.budgetFill}
              style={{
                width: `${Math.min(100, status.budget.pct_used)}%`,
                background: budgetColor,
              }}
            />
          </div>
          <div className={s.budgetRemaining}>
            {formatTokens(status.budget.remaining)} remaining
          </div>
        </div>
      )}

      {/* Two-column layout */}
      <div className={s.twoCol}>
        {/* Daily chart */}
        <div className={s.chartPanel}>
          <div className={s.panelTitle}>Daily Token Usage</div>
          <DailyChart daily={usage?.daily || []} />
        </div>

        {/* Model breakdown */}
        <div className={s.modelPanel}>
          <div className={s.panelTitle}>Model Split</div>
          <ModelBreakdown byModel={usage?.by_model || []} />
          {(!usage?.by_model || usage.by_model.length === 0) && (
            <div className={s.noData}>No model usage data yet</div>
          )}
        </div>
      </div>
    </div>
  );
}
